mapper.select:
SELECT a.ASSET_SEQ, a.FAMILY_ID, a.ASSET_NM, a.ASSET_TYPE, t.ASSET_TYPE_NM, a.LIQUID_YN, a.AMOUNT, a.MEMO, a.EXPECTED_RATE, a.RATE_CYCLE_NUM, a.RATE_CYCLE_UNIT, a.DEL_YN, a.DISPOSE_YN, a.DISPOSE_YMD, a.DISPOSE_REASON, a.REG_ID, a.REG_DT, a.UPD_ID, a.UPD_DT, DATE_FORMAT(a.UPD_DT, '%Y-%m-%d') AS UPD_DT_STR FROM ASSET_MST a LEFT JOIN ASSET_TYPE_CD t ON a.ASSET_TYPE = t.ASSET_TYPE WHERE a.FAMILY_ID = #{familyId} AND a.DEL_YN = 'N'
AND a.DISPOSE_YN = #{disposeYn}
ORDER BY a.DISPOSE_YN ASC, a.ASSET_SEQ DESC

mapper.update:
UPDATE ASSET_MST
SET DEL_YN = 'Y',
    UPD_ID = #{updId},
    UPD_DT = NOW()
WHERE FAMILY_ID = #{familyId}
  AND ASSET_SEQ = #{assetSeq}

mapper.select:
SELECT LOAN_SEQ, FAMILY_ID, LOAN_NM, LOAN_AMOUNT, CURRENT_BALANCE, INTEREST_RATE, LOAN_MONTHS, START_YMD, END_YMD, MEMO, DEL_YN, CLOSE_YN, CLOSE_YMD, CLOSE_REASON, REG_ID, REG_DT, UPD_ID, UPD_DT, DATE_FORMAT(UPD_DT, '%Y-%m-%d') AS UPD_DT_STR FROM LOAN_MST WHERE FAMILY_ID = #{familyId} AND DEL_YN = 'N'
AND CLOSE_YN = #{closeYn}
ORDER BY CLOSE_YN ASC, LOAN_SEQ DESC

mapper.update:
UPDATE LOAN_MST
SET DEL_YN = 'Y',
    UPD_ID = #{updId},
    UPD_DT = NOW()
WHERE FAMILY_ID = #{familyId}
  AND LOAN_SEQ  = #{loanSeq}
